import React, { useEffect, useState, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { ArrowLeft, Send, Paperclip, GitPullRequest, CheckCircle, XCircle, Clock, Trash2, Edit3 } from 'lucide-react';
import toast from 'react-hot-toast';
import { tasksApi, commentsApi, reviewsApi, attachmentsApi } from '../services/api';
import { useAuth } from '../context/AuthContext';
import {
  getInitials, getStatusLabel, getStatusClass, getPriorityClass,
  formatRelativeTime, formatDate, formatBytes, getErrorMessage
} from '../utils/helpers';

const STATUSES = ['TODO', 'IN_PROGRESS', 'REVIEW', 'DONE'];

export default function TaskDetailPage() {
  const { projectId, taskId } = useParams();
  const navigate = useNavigate();
  const { user } = useAuth();

  const [task, setTask]               = useState(null);
  const [comments, setComments]       = useState([]);
  const [reviews, setReviews]         = useState([]);
  const [attachments, setAttachments] = useState([]);
  const [loading, setLoading]         = useState(true);
  const [commentText, setCommentText] = useState('');
  const [sending, setSending]         = useState(false);
  const [tab, setTab]                 = useState('comments');
  const [reviewComment, setReviewComment] = useState('');
  const [githubPR, setGithubPR]       = useState('');

  const load = useCallback(async () => {
    try {
      const [tRes, cRes, rRes, aRes] = await Promise.all([
        tasksApi.get(projectId, taskId),
        commentsApi.list(projectId, taskId),
        reviewsApi.list(projectId, taskId),
        attachmentsApi.list(projectId, taskId),
      ]);
      setTask(tRes.data.task);
      setComments(cRes.data.comments || []);
      setReviews(rRes.data.reviews || []);
      setAttachments(aRes.data.attachments || []);
    } catch { toast.error('Failed to load task'); }
    finally { setLoading(false); }
  }, [projectId, taskId]);

  useEffect(() => { load(); }, [load]);

  const handleStatusChange = async (status) => {
    try {
      const { data } = await tasksApi.updateStatus(projectId, taskId, status);
      setTask(data.task);
      toast.success(`Status → ${getStatusLabel(status)}`);
    } catch (err) { toast.error(getErrorMessage(err)); }
  };

  const handleComment = async (e) => {
    e.preventDefault();
    if (!commentText.trim()) return;
    setSending(true);
    try {
      const { data } = await commentsApi.create(projectId, taskId, { content: commentText });
      setComments(prev => [data.comment, ...prev]);
      setCommentText('');
    } catch (err) { toast.error(getErrorMessage(err)); }
    finally { setSending(false); }
  };

  const handleDeleteComment = async (id) => {
    try {
      await commentsApi.delete(projectId, taskId, id);
      setComments(prev => prev.filter(c => c._id !== id));
      toast.success('Comment deleted');
    } catch (err) { toast.error(getErrorMessage(err)); }
  };

  const handleSubmitReview = async () => {
    try {
      const { data } = await reviewsApi.submit(projectId, taskId, { githubPR });
      setReviews(prev => [data.review, ...prev]);
      setTask(data.task);
      toast.success('Submitted for review');
    } catch (err) { toast.error(getErrorMessage(err)); }
  };

  const handleReviewAction = async (reviewId, action) => {
    try {
      const { data } = await reviewsApi.action(projectId, taskId, reviewId, { action, comment: reviewComment });
      setReviews(prev => prev.map(r => r._id === reviewId ? data.review : r));
      setTask(data.task);
      setReviewComment('');
      toast.success(action === 'APPROVED' ? '✅ Approved!' : '🔄 Changes requested');
    } catch (err) { toast.error(getErrorMessage(err)); }
  };

  const handleFileUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const form = new FormData();
    form.append('file', file);
    try {
      const { data } = await attachmentsApi.upload(projectId, taskId, form);
      setAttachments(prev => [data.attachment, ...prev]);
      toast.success('File uploaded');
    } catch (err) { toast.error(getErrorMessage(err)); }
  };

  const handleDeleteAttachment = async (id) => {
    try {
      await attachmentsApi.delete(projectId, taskId, id);
      setAttachments(prev => prev.filter(a => a._id !== id));
      toast.success('Attachment deleted');
    } catch (err) { toast.error(getErrorMessage(err)); }
  };

  if (loading) return <div className="empty-state"><div className="spinner spinner-lg" /></div>;
  if (!task) return <div className="empty-state"><p>Task not found</p></div>;

  const pendingReview = reviews.find(r => r.status === 'PENDING');

  return (
    <div style={{ maxWidth: 900, margin: '0 auto' }}>
      {/* Back */}
      <button className="btn btn-ghost btn-sm" style={{ marginBottom: '1rem' }}
        onClick={() => navigate(`/projects/${projectId}`)}>
        <ArrowLeft size={14} /> Back to project
      </button>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 280px', gap: '1.5rem', alignItems: 'start' }}>
        {/* Main */}
        <div>
          <div className="card" style={{ marginBottom: '1rem' }}>
            {/* Task header */}
            <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 12 }}>
              <span style={{ fontSize: '0.75rem', color: 'var(--text-muted)', fontFamily: 'var(--font-mono)' }}>
                #{task.taskNumber}
              </span>
              <span className={`badge ${getStatusClass(task.status)}`}>{getStatusLabel(task.status)}</span>
              <span className={`badge ${getPriorityClass(task.priority)}`}>{task.priority}</span>
            </div>
            <h2 style={{ fontSize: '1.2rem', marginBottom: '0.75rem' }}>{task.title}</h2>
            {task.description ? (
              <p style={{ color: 'var(--text-secondary)', fontSize: '0.9rem', lineHeight: 1.65, whiteSpace: 'pre-wrap' }}>
                {task.description}
              </p>
            ) : (
              <p style={{ color: 'var(--text-muted)', fontSize: '0.875rem', fontStyle: 'italic' }}>No description</p>
            )}
            {task.githubPR && (
              <a href={task.githubPR} target="_blank" rel="noreferrer"
                style={{ display: 'inline-flex', alignItems: 'center', gap: 6, marginTop: 12,
                  fontSize: '0.82rem', color: 'var(--accent)' }}>
                <GitPullRequest size={14} /> {task.githubPR}
              </a>
            )}
          </div>

          {/* Tabs */}
          <div className="tabs" style={{ marginBottom: '1rem' }}>
            {['comments','reviews','attachments','history'].map(t => (
              <button key={t} className={`tab-btn${tab === t ? ' active' : ''}`} onClick={() => setTab(t)}>
                {t.charAt(0).toUpperCase() + t.slice(1)}
                {t === 'comments' && comments.length > 0 && ` (${comments.length})`}
                {t === 'attachments' && attachments.length > 0 && ` (${attachments.length})`}
              </button>
            ))}
          </div>

          {/* Comments */}
          {tab === 'comments' && (
            <div>
              <form onSubmit={handleComment} style={{ display: 'flex', gap: 10, marginBottom: '1.25rem' }}>
                <div className="avatar">{getInitials(user?.name)}</div>
                <div style={{ flex: 1, display: 'flex', flexDirection: 'column', gap: 8 }}>
                  <textarea className="input" rows={2} placeholder="Write a comment…"
                    value={commentText} onChange={e => setCommentText(e.target.value)} />
                  <div style={{ display: 'flex', justifyContent: 'flex-end' }}>
                    <button type="submit" className="btn btn-primary btn-sm" disabled={sending || !commentText.trim()}>
                      {sending ? <span className="spinner" /> : <><Send size={13} /> Post</>}
                    </button>
                  </div>
                </div>
              </form>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
                {comments.map(c => (
                  <div key={c._id} className="comment-item">
                    <div className="avatar avatar-sm">{getInitials(c.author?.name)}</div>
                    <div className="comment-body">
                      <div className="comment-header">
                        <div>
                          <span className="comment-author">{c.author?.name}</span>
                          <span className="comment-time" style={{ marginLeft: 8 }}>{formatRelativeTime(c.createdAt)}</span>
                          {c.isEdited && <span style={{ fontSize: '0.7rem', color: 'var(--text-muted)', marginLeft: 6 }}>(edited)</span>}
                        </div>
                        {c.author?._id === user?._id && (
                          <button className="btn btn-ghost btn-icon btn-sm"
                            onClick={() => handleDeleteComment(c._id)}>
                            <Trash2 size={13} />
                          </button>
                        )}
                      </div>
                      <p className="comment-content">{c.content}</p>
                    </div>
                  </div>
                ))}
                {comments.length === 0 && <div className="empty-state" style={{ padding: '2rem' }}><p>No comments yet</p></div>}
              </div>
            </div>
          )}

          {/* Reviews */}
          {tab === 'reviews' && (
            <div>
              {task.status !== 'REVIEW' && task.status !== 'DONE' && (
                <div className="card" style={{ marginBottom: '1rem' }}>
                  <h3 style={{ fontSize: '0.9rem', marginBottom: '0.75rem' }}>Submit for Review</h3>
                  <input className="input" placeholder="GitHub PR URL (optional)" value={githubPR}
                    onChange={e => setGithubPR(e.target.value)} style={{ marginBottom: 8 }} />
                  <button className="btn btn-primary btn-sm" onClick={handleSubmitReview}>
                    <GitPullRequest size={14} /> Submit for Review
                  </button>
                </div>
              )}

              {pendingReview && (
                <div className="card" style={{ marginBottom: '1rem', borderColor: 'var(--border-light)' }}>
                  <h3 style={{ fontSize: '0.9rem', marginBottom: '0.75rem', color: 'var(--purple)' }}>
                    🔍 Review in Progress
                  </h3>
                  <textarea className="input" rows={2} placeholder="Review comment…"
                    value={reviewComment} onChange={e => setReviewComment(e.target.value)}
                    style={{ marginBottom: 8 }} />
                  <div style={{ display: 'flex', gap: 8 }}>
                    <button className="btn btn-sm" style={{ background: 'var(--green-dim)', color: 'var(--green)', borderColor: 'transparent' }}
                      onClick={() => handleReviewAction(pendingReview._id, 'APPROVED')}>
                      <CheckCircle size={14} /> Approve
                    </button>
                    <button className="btn btn-sm" style={{ background: 'var(--red-dim)', color: 'var(--red)', borderColor: 'transparent' }}
                      onClick={() => handleReviewAction(pendingReview._id, 'CHANGES_REQUESTED')}>
                      <XCircle size={14} /> Request Changes
                    </button>
                  </div>
                </div>
              )}

              {reviews.map(r => (
                <div key={r._id} className="review-card" style={{ marginBottom: '0.75rem' }}>
                  <div className="review-card-header">
                    <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                      <div className="avatar avatar-sm">{getInitials(r.submittedBy?.name)}</div>
                      <span style={{ fontSize: '0.85rem', fontWeight: 500 }}>{r.submittedBy?.name}</span>
                    </div>
                    <span className={`badge ${r.status === 'APPROVED' ? 'badge-done' : r.status === 'PENDING' ? 'badge-review' : 'badge-high'}`}>
                      {r.status.replace('_', ' ')}
                    </span>
                  </div>
                  {r.history?.map((h, i) => (
                    <div key={i} className="review-history-item">
                      <div className="avatar avatar-sm">{getInitials(h.reviewer?.name)}</div>
                      <div>
                        <span style={{ fontSize: '0.8rem', fontWeight: 500, color: 'var(--text-primary)' }}>{h.action}</span>
                        {h.comment && <p style={{ fontSize: '0.8rem', color: 'var(--text-secondary)', marginTop: 2 }}>{h.comment}</p>}
                        <p style={{ fontSize: '0.72rem', color: 'var(--text-muted)', marginTop: 2 }}>{formatRelativeTime(h.timestamp)}</p>
                      </div>
                    </div>
                  ))}
                </div>
              ))}
              {reviews.length === 0 && <div className="empty-state" style={{ padding: '2rem' }}><p>No review history</p></div>}
            </div>
          )}

          {/* Attachments */}
          {tab === 'attachments' && (
            <div>
              <label className="btn btn-secondary" style={{ cursor: 'pointer', marginBottom: '1rem' }}>
                <Paperclip size={14} /> Upload File
                <input type="file" style={{ display: 'none' }} onChange={handleFileUpload} />
              </label>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                {attachments.map(a => (
                  <div key={a._id} className="card" style={{ padding: '0.75rem', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                      <Paperclip size={16} style={{ color: 'var(--text-muted)' }} />
                      <div>
                        <p style={{ fontSize: '0.875rem', fontWeight: 500 }}>{a.originalName}</p>
                        <p style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>
                          {formatBytes(a.size)} · {a.uploadedBy?.name} · {formatRelativeTime(a.createdAt)}
                        </p>
                      </div>
                    </div>
                    <button className="btn btn-ghost btn-icon btn-sm"
                      onClick={() => handleDeleteAttachment(a._id)}>
                      <Trash2 size={13} />
                    </button>
                  </div>
                ))}
                {attachments.length === 0 && <div className="empty-state" style={{ padding: '2rem' }}><p>No attachments</p></div>}
              </div>
            </div>
          )}

          {/* History */}
          {tab === 'history' && (
            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
              {(task.statusHistory || []).map((h, i) => (
                <div key={i} style={{ display: 'flex', alignItems: 'center', gap: 10, padding: '0.65rem 0', borderBottom: '1px solid var(--border)' }}>
                  <Clock size={14} style={{ color: 'var(--text-muted)', flexShrink: 0 }} />
                  <span style={{ fontSize: '0.82rem', color: 'var(--text-secondary)' }}>
                    <strong style={{ color: 'var(--text-primary)' }}>{h.changedBy?.name || 'Someone'}</strong>
                    {' '}moved from{' '}
                    <span className={`badge ${getStatusClass(h.from)}`}>{getStatusLabel(h.from)}</span>
                    {' '}to{' '}
                    <span className={`badge ${getStatusClass(h.to)}`}>{getStatusLabel(h.to)}</span>
                  </span>
                  <span style={{ marginLeft: 'auto', fontSize: '0.72rem', color: 'var(--text-muted)' }}>
                    {formatRelativeTime(h.changedAt)}
                  </span>
                </div>
              ))}
              {(!task.statusHistory || task.statusHistory.length === 0) && (
                <div className="empty-state" style={{ padding: '2rem' }}><p>No status changes yet</p></div>
              )}
            </div>
          )}
        </div>

        {/* Sidebar */}
        <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
          <div className="card">
            <div style={{ marginBottom: '1rem' }}>
              <p className="form-label" style={{ marginBottom: 6 }}>Status</p>
              <select className="input" value={task.status} onChange={e => handleStatusChange(e.target.value)}>
                {STATUSES.map(s => <option key={s} value={s}>{getStatusLabel(s)}</option>)}
              </select>
            </div>
            <div style={{ marginBottom: '1rem' }}>
              <p className="form-label" style={{ marginBottom: 4 }}>Priority</p>
              <span className={`badge ${getPriorityClass(task.priority)}`}>{task.priority}</span>
            </div>
            <div style={{ marginBottom: '1rem' }}>
              <p className="form-label" style={{ marginBottom: 4 }}>Reporter</p>
              <div style={{ display: 'flex', alignItems: 'center', gap: 7 }}>
                <div className="avatar avatar-sm">{getInitials(task.reporter?.name)}</div>
                <span style={{ fontSize: '0.82rem', color: 'var(--text-secondary)' }}>{task.reporter?.name}</span>
              </div>
            </div>
            {task.assignee && (
              <div style={{ marginBottom: '1rem' }}>
                <p className="form-label" style={{ marginBottom: 4 }}>Assignee</p>
                <div style={{ display: 'flex', alignItems: 'center', gap: 7 }}>
                  <div className="avatar avatar-sm">{getInitials(task.assignee?.name)}</div>
                  <span style={{ fontSize: '0.82rem', color: 'var(--text-secondary)' }}>{task.assignee?.name}</span>
                </div>
              </div>
            )}
            {task.dueDate && (
              <div>
                <p className="form-label" style={{ marginBottom: 4 }}>Due Date</p>
                <span style={{ fontSize: '0.85rem', color: 'var(--text-secondary)' }}>{formatDate(task.dueDate)}</span>
              </div>
            )}
          </div>

          <div className="card">
            <p className="form-label" style={{ marginBottom: 8 }}>Created</p>
            <span style={{ fontSize: '0.82rem', color: 'var(--text-secondary)' }}>{formatRelativeTime(task.createdAt)}</span>
            <p className="form-label" style={{ marginTop: 10, marginBottom: 4 }}>Updated</p>
            <span style={{ fontSize: '0.82rem', color: 'var(--text-secondary)' }}>{formatRelativeTime(task.updatedAt)}</span>
          </div>
        </div>
      </div>
    </div>
  );
}
